pinchtab eval "
(() => {
    const acceptedAnswer = document.querySelector('.answer.accepted-answer');
    if (!acceptedAnswer) {
        // Fallback: search for the first answer or any checkmark
        const checkmark = document.querySelector('.js-accepted-answer-indicator');
        const firstAnswer = document.querySelector('.answer');
        return { 
            error: 'Accepted answer not found via .accepted-answer',
            hasCheckmark: !!checkmark,
            firstAnswerId: firstAnswer ? firstAnswer.id : null
        };
    }

    const votes = acceptedAnswer.getAttribute('data-score') || 
                  acceptedAnswer.querySelector('.js-vote-count')?.getAttribute('data-value') ||
                  acceptedAnswer.querySelector('.js-vote-count')?.innerText?.trim();

    const authorElement = acceptedAnswer.querySelector('.user-details a');
    const author = authorElement ? authorElement.innerText.trim() : 'Unknown';

    const codeBlocks = acceptedAnswer.querySelectorAll('pre code').length;

    const answersHeader = document.querySelector('#answers-header h2')?.innerText?.match(/\d+/)?.[0] || 
                          document.querySelector('.js-answers-count')?.innerText?.trim();

    return {
        votes,
        author,
        codeBlocks,
        totalAnswers: answersHeader
    };
})()
"

pinchtab eval "
(() => {
    // Mysticial is the famous author of the accepted answer.
    // Let's find the answer by Mysticial.
    const answers = Array.from(document.querySelectorAll('.answer'));
    const mysticialAnswer = answers.find(a => a.innerText.includes('Mysticial'));

    if (!mysticialAnswer) return { error: 'Mysticial answer not found' };

    const votes = mysticialAnswer.getAttribute('data-score') || 
                  mysticialAnswer.querySelector('.js-vote-count')?.innerText?.trim();

    const authorElement = mysticialAnswer.querySelector('.user-details a');
    const author = authorElement ? authorElement.innerText.trim() : 'Unknown';

    const codeBlocks = mysticialAnswer.querySelectorAll('pre code').length;

    const answersHeader = document.querySelector('#answers-header h2')?.innerText?.match(/\d+/)?.[0] || 
                          document.querySelector('.js-answers-count')?.innerText?.trim();

    return {
        votes,
        author,
        codeBlocks,
        totalAnswers: answersHeader,
        isAccepted: mysticialAnswer.classList.contains('accepted-answer')
    };
})()
"

pinchtab eval "
(() => {
    // Let's find the answer with the checkmark (accepted)
    const acceptedAnswer = document.querySelector('.answer.accepted-answer');
    if (!acceptedAnswer) return { error: 'Accepted answer not found' };

    const votes = acceptedAnswer.getAttribute('data-score') || 
                  acceptedAnswer.querySelector('.js-vote-count')?.innerText?.trim();

    // The author is in the user-info block. There might be multiple (edited by, original author).
    // The original author is usually the last user-info block.
    const userInfos = acceptedAnswer.querySelectorAll('.user-info');
    const authorBlock = userInfos[userInfos.length - 1];
    const authorLink = authorBlock.querySelector('.user-details a');
    const author = authorLink ? authorLink.innerText.trim() : 'Unknown';

    const codeBlocks = acceptedAnswer.querySelectorAll('pre code').length;

    const answersHeader = document.querySelector('#answers-header h2')?.innerText?.match(/\d+/)?.[0] || 
                          document.querySelector('.js-answers-count')?.innerText?.trim();

    return {
        votes,
        author,
        codeBlocks,
        totalAnswers: answersHeader,
        authorBlockText: authorBlock.innerText
    };
})()
"

